    "/rest/3/artifacts": {
        parameters: {
            query?: never;
            header?: never;
            path?: never;
            cookie?: never;
        };
        get?: never;
        put?: never;
        /**
         * Upload an app artifact
         * @description Upload an app artifact so that it can be used by an app software version.
         *
         *     This endpoint allows developers to upload artifact files that can be used in their app software versions including:
         *     - JAR files for server apps
         *     - OBR (OSGi Bundle Repository) files
         *     - JWB (Jira Web Fragments Bundle) files
         *     - Connect descriptor JSON files
         *
         *     **Format**: The file should be uploaded as multipart/form-data
         *
         *     **File size restrictions:**
         *     - Maximum individual artifact size: 250 MB
         *     - Upload rate limit: ~750 MB per 2-hour period
         *     - Minimum wait time between uploads: 10 seconds
         *
         *     The request body is a multipart/form-data with the following key:
         *     - **file**: Multipart file to be uploaded
         *
         *     The uploaded artifact will be processed, validated, and stored, returning details that can be used in app software version APIs.
         *
         *     **Usage Examples:**
         *
         *     ```bash
         *     curl --request POST \
         *       --url 'https://api.atlassian.com/rest/3/artifacts' \
         *       --user 'email@example.com:<api_token>' \
         *       --header 'Accept: application/json' \
         *       --form 'file=@/path/to/your/app.jar'
         *     ```
         */
        post: {
            parameters: {
                query?: never;
                header?: never;
                path?: never;
                cookie?: never;
            };
            requestBody: {
                content: {
                    "multipart/form-data": {
                        /**
                         * Format: binary
                         * @description Artifact file to be uploaded (JAR, OBR, JWB, JSON, etc.)
                         */
                        file: string;
                    };
                };
            };
            responses: {
                /** @description Artifact successfully uploaded */
                200: {
                    headers: {
                        [name: string]: unknown;
                    };
                    content: {
                        /**
                         * @example {
                         *       "fileInfo": {
                         *         "logicalFileName": "my-app.jar",
                         *         "size": 1048576,
                         *         "checksum": "sha512:cf83e1357eefb8bdf1542850d66d8007d620e4050b5715dc83f4a921d36ce9ce47d0d13c5d85f2b0ff8318d2877eec2f63b931bd47417a81a538327af927da3e"
                         *       },
                         *       "details": {
                         *         "key": "my.app.key",
                         *         "name": "my-app",
                         *         "version": "1.0.0",
                         *         "licensingEnabled": true,
                         *         "dataCenterCompatible": true,
                         *         "addOnType": "two",
                         *         "remotable": false,
                         *         "dataCenterStatus": "compatible",
                         *         "editionsEnabled": false
                         *       },
                         *       "_links": {
                         *         "self": {
                         *           "href": "/rest/3/artifacts/337c40d8-c903-4e28-8498-7cbc372ba578"
                         *         },
                         *         "binary": {
                         *           "href": "/rest/3/artifacts/337c40d8-c903-4e28-8498-7cbc372ba578/download"
                         *         }
                         *       }
                         *     }
                         */
                        "application/json": components["schemas"]["UploadedSoftwareArtifact"];
                    };
                };
                /** @description Bad request - invalid artifact file or validation errors */
                400: {
                    headers: {
                        [name: string]: unknown;
                    };
                    content: {
                        /**
                         * @example {
                         *       "errors": [
                         *         {
                         *           "id": "4d5e6f7a-8b9c-0d1e-2f3a-4b5c6d7e8f9a",
                         *           "status": "400",
                         *           "code": "VALIDATION_ERROR",
                         *           "title": "Invalid artifact file",
                         *           "detail": "The uploaded file is not a valid artifact format"
                         *         }
                         *       ]
                         *     }
                         */
                        "application/json": components["schemas"]["ErrorResponse"];
                    };
                };
                /** @description Unauthenticated */
                401: {
                    headers: {
                        [name: string]: unknown;
                    };
                    content?: never;
                };
                /** @description Forbidden */
                403: {
                    headers: {
                        [name: string]: unknown;
                    };
                    content?: never;
                };
                /** @description Payload too large - artifact file exceeds size limit */
                413: {
                    headers: {
                        [name: string]: unknown;
                    };
                    content: {
                        "application/json": components["schemas"]["ErrorResponse"];
                    };
                };
            };
        };
        delete?: never;
        options?: never;
        head?: never;
        patch?: never;
        trace?: never;
    };
